"use strict";(globalThis.webpackChunkai_systems_engineering=globalThis.webpackChunkai_systems_engineering||[]).push([[2393],{2563(e,n,t){t.r(n),t.d(n,{assets:()=>d,contentTitle:()=>s,default:()=>h,frontMatter:()=>o,metadata:()=>r,toc:()=>l});const r=JSON.parse('{"id":"model-inference-core/transformer","title":"Transformer architecture","description":"---","source":"@site/topics/01-model-inference-core/transformer.md","sourceDirName":"01-model-inference-core","slug":"/model-inference-core/transformer","permalink":"/ai-systems-engineering/docs/model-inference-core/transformer","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":4,"frontMatter":{"sidebar_position":4},"sidebar":"topicsSidebar","previous":{"title":"Embeddings","permalink":"/ai-systems-engineering/docs/model-inference-core/embeddings"},"next":{"title":"Attention mechanism","permalink":"/ai-systems-engineering/docs/model-inference-core/attention-mechanism"}}');var a=t(4848),i=t(8453);const o={sidebar_position:4},s="Transformer architecture",d={},l=[{value:"What it is",id:"what-it-is",level:2},{value:"How it works",id:"how-it-works",level:2},{value:"The three variants",id:"the-three-variants",level:3},{value:"Forward pass through one decoder block",id:"forward-pass-through-one-decoder-block",level:3},{value:"What each block component does",id:"what-each-block-component-does",level:3},{value:"Parameter distribution: where the weights actually live",id:"parameter-distribution-where-the-weights-actually-live",level:3},{value:"Modern evolution (2023\u20132025)",id:"modern-evolution-20232025",level:3},{value:"What the 2017 paper got right and wrong",id:"what-the-2017-paper-got-right-and-wrong",level:3},{value:"Gotchas &amp; production behavior",id:"gotchas--production-behavior",level:3},{value:"Why it matters",id:"why-it-matters",level:2},{value:"Key terms",id:"key-terms",level:2},{value:"Code / demo",id:"code--demo",level:2},{value:"My notes",id:"my-notes",level:2},{value:"Resources",id:"resources",level:2}];function c(e){const n={a:"a",code:"code",em:"em",h1:"h1",h2:"h2",h3:"h3",header:"header",hr:"hr",img:"img",li:"li",mermaid:"mermaid",ol:"ol",p:"p",pre:"pre",strong:"strong",table:"table",tbody:"tbody",td:"td",th:"th",thead:"thead",tr:"tr",ul:"ul",...(0,i.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(n.header,{children:(0,a.jsx)(n.h1,{id:"transformer-architecture",children:"Transformer architecture"})}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.h2,{id:"what-it-is",children:"What it is"}),"\n",(0,a.jsx)(n.p,{children:"Think of a transformer like a document review committee where every reviewer can instantly read and cross-reference every part of the document simultaneously \u2014 rather than reading it word by word from left to right the way a human editor would."}),"\n",(0,a.jsx)(n.p,{children:"A transformer is a neural network architecture built from a stack of identical blocks, each combining a self-attention sublayer (which routes information between token positions) and a feed-forward network sublayer (which processes each position independently), connected by residual connections and layer normalization."}),"\n",(0,a.jsx)(n.p,{children:"It is not a single architecture \u2014 the term covers three distinct variants (encoder-only, decoder-only, and encoder-decoder) that share a block structure but differ fundamentally in what their attention layers are allowed to see and in whether they can generate text autoregressively."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.h2,{id:"how-it-works",children:"How it works"}),"\n",(0,a.jsx)(n.h3,{id:"the-three-variants",children:"The three variants"}),"\n",(0,a.jsx)(n.p,{children:"Every transformer variant is built from the same four primitives repeated across N layers: self-attention, a feed-forward network (FFN), layer normalization, and residual connections. What distinguishes the variants is the attention mask and the presence or absence of cross-attention."}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.img,{alt:"Three transformer architecture variants side by side: encoder-only, decoder-only, and encoder-decoder",src:t(1550).A+"",width:"960",height:"850"})}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.strong,{children:"Encoder-only (BERT, RoBERTa, ModernBERT)"})}),"\n",(0,a.jsx)(n.p,{children:"Every token in the input attends to every other token \u2014 past and future \u2014 simultaneously. This bidirectional attention produces a sequence of contextualized hidden states, one per input token, that are then passed to a task-specific head for classification, tagging, or embedding extraction. Encoder-only models cannot generate text autoregressively \u2014 they have no causal structure. They are the right tool for classification, named entity recognition, semantic search, and embedding generation where labeled data is available."}),"\n",(0,a.jsx)(n.p,{children:"BERT-base: 12 layers, d_model = 768, d_ff = 3,072, 12 attention heads, 110M parameters.\nBERT-large: 24 layers, d_model = 1,024, d_ff = 4,096, 16 heads, 340M parameters."}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.strong,{children:"Decoder-only (GPT, LLaMA, Mistral, DeepSeek, Gemma)"})}),"\n",(0,a.jsx)(n.p,{children:"Each token can only attend to itself and tokens that came before it. This causal (masked) self-attention is enforced by a triangular mask applied to the attention score matrix before softmax \u2014 all future positions are set to -inf and vanish after softmax. There is no cross-attention sublayer. This structure makes decoder-only models the correct choice for autoregressive text generation."}),"\n",(0,a.jsx)(n.p,{children:"LLaMA 3 8B: 32 layers, d_model = 4,096, 32 query heads / 8 KV heads (GQA), 8B parameters.\nLLaMA 3 70B: 80 layers, d_model = 8,192, 64 query heads / 8 KV heads, 70B parameters.\nGPT-3: 96 layers, d_model = 12,288, 175B parameters."}),"\n",(0,a.jsxs)(n.p,{children:["\u2192 see ",(0,a.jsx)(n.a,{href:"/ai-systems-engineering/docs/model-inference-core/autoregressive-decoding",children:"Autoregressive decoding"})," for how the causal mask enables token-by-token generation."]}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.strong,{children:"Encoder-decoder (T5, BART, original 2017 Transformer)"})}),"\n",(0,a.jsx)(n.p,{children:"The encoder stack processes the full input with bidirectional attention, producing a sequence of hidden states. The decoder stack then generates output autoregressively using two attention sublayers per block: causal self-attention over the partially generated output, plus cross-attention where decoder queries attend over all encoder output states. That cross-attention connection is how the decoder accesses the encoded input at every generation step. The extra sublayer makes encoder-decoder decoder blocks roughly 50% more expensive per layer than decoder-only blocks. This architecture retains a niche in structured sequence-to-sequence tasks (translation, summarization with structured output, code generation from formal specs)."}),"\n",(0,a.jsx)(n.p,{children:"Original 2017 model: 6 encoder + 6 decoder layers, d_model = 512, d_ff = 2,048, 8 heads."}),"\n",(0,a.jsx)(n.h3,{id:"forward-pass-through-one-decoder-block",children:"Forward pass through one decoder block"}),"\n",(0,a.jsx)(n.mermaid,{value:'flowchart TD\n    A["Token IDs\\n[42, 1731, 89, ...]"] --\x3e B["Embedding Lookup\\n(vocab_size \xd7 d_model table)"]\n    B --\x3e C["+ Positional Encoding\\n(sinusoidal or learned RoPE)"]\n    C --\x3e D["Masked Self-Attention\\n(Q, K, V projections \u2192 scaled dot-product\\ncausal mask zeroes future positions)"]\n\n    C --\x3e|residual| E["Add & LayerNorm\\n(x + Attn(x))"]\n    D --\x3e E\n\n    E --\x3e F["Feed-Forward Network\\nLinear(d_model \u2192 4\xd7d_model)\\n\u2192 Activation (GeLU / SiLU)\\n\u2192 Linear(4\xd7d_model \u2192 d_model)"]\n\n    E --\x3e|residual| G["Add & LayerNorm\\n(x + FFN(x))"]\n    F --\x3e G\n\n    G --\x3e H{"More blocks?"}\n    H --\x3e|"Yes \u2014 repeat \xd7 N"| D\n    H --\x3e|"No"| I["Linear projection\\n(d_model \u2192 vocab_size)\\n\u2192 Softmax \u2192 logits"]\n    I --\x3e J["Next token prediction\\n(sample or argmax)"]\n\n    style A fill:#dbeafe,stroke:#3b82f6,color:#1e3a5f\n    style B fill:#dbeafe,stroke:#3b82f6,color:#1e3a5f\n    style C fill:#dbeafe,stroke:#3b82f6,color:#1e3a5f\n    style D fill:#dcfce7,stroke:#16a34a,color:#052e16\n    style E fill:#f1f5f9,stroke:#64748b,color:#0f172a\n    style F fill:#dcfce7,stroke:#16a34a,color:#052e16\n    style G fill:#f1f5f9,stroke:#64748b,color:#0f172a\n    style H fill:#ede9fe,stroke:#8b5cf6,color:#2e1065\n    style I fill:#dcfce7,stroke:#16a34a,color:#052e16\n    style J fill:#dcfce7,stroke:#16a34a,color:#052e16'}),"\n",(0,a.jsx)(n.h3,{id:"what-each-block-component-does",children:"What each block component does"}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Self-attention sublayer"})," routes information between token positions by computing compatibility scores between every pair of positions in the sequence. \u2192 see ",(0,a.jsx)(n.a,{href:"/ai-systems-engineering/docs/model-inference-core/attention-mechanism",children:"Attention mechanism"})," for the Q, K, V projection mechanics and scaled dot-product computation."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Feed-forward network (FFN) sublayer"})," applies the same two-layer fully connected network independently to each token position. It does not exchange information between positions \u2014 it deepens each position's representation in isolation. The original transformer used ReLU activation with d_ff = 4 \xd7 d_model, giving an FFN expansion ratio of 4. Modern LLMs use SwiGLU activation, which shifts the expansion ratio to (8/3) \xd7 d_model but adds a gating projection, keeping total parameters similar."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Layer normalization"})," stabilizes activations. The original paper applied normalization after each sublayer (post-norm). Post-norm became dominant in BERT but was replaced by pre-norm (applying normalization to the input of each sublayer) in GPT-2 onward because pre-norm prevents gradient explosion in very deep models and trains stably without mandatory warmup schedules. As of 2025, ~77.4% of models use RMSNorm (a simpler variant of LayerNorm with no mean-centering)."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Residual connections"})," wrap every sublayer: ",(0,a.jsx)(n.code,{children:"output = x + SubLayer(x)"}),". Gradients flow directly back through the network without passing through the sublayer computation, which is what makes 96+ layer models trainable. The more accurate mental model: the layers are writing refinements (deltas) to a shared residual stream that passes through largely unchanged \u2014 not transforming the representation wholesale at every step."]}),"\n",(0,a.jsx)(n.h3,{id:"parameter-distribution-where-the-weights-actually-live",children:"Parameter distribution: where the weights actually live"}),"\n",(0,a.jsx)(n.p,{children:'The title "Attention Is All You Need" creates a persistent wrong intuition. In practice, the FFN sublayer holds roughly twice the parameters of the self-attention sublayer per layer.'}),"\n",(0,a.jsx)(n.p,{children:"Per-layer parameter counts at d_model = d (approximate):"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsx)(n.li,{children:"Multi-head attention (Q, K, V, O projections): \u2248 4d\xb2"}),"\n",(0,a.jsx)(n.li,{children:"FFN (two linear layers with 4\xd7 expansion): \u2248 8d\xb2"}),"\n",(0,a.jsxs)(n.li,{children:["FFN",":attention"," ratio \u2248 ",(0,a.jsx)(n.strong,{children:"2:1"})]}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:"In LLaMA 3 8B across all 32 layers:"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsx)(n.li,{children:"Attention parameters: ~1,344M (~17% of total)"}),"\n",(0,a.jsx)(n.li,{children:"FFN parameters: ~5,632M (~70% of total)"}),"\n",(0,a.jsx)(n.li,{children:"Embedding + output head: ~13%"}),"\n"]}),"\n",(0,a.jsxs)(n.p,{children:["This has direct implications for compression work: pruning attention aggressively while leaving FFN intact misses the dominant parameter mass. \u2192 see ",(0,a.jsx)(n.a,{href:"/ai-systems-engineering/docs/model-inference-core/attention-mechanism",children:"Attention mechanism"})," for per-head parameter breakdowns."]}),"\n",(0,a.jsx)(n.h3,{id:"modern-evolution-20232025",children:"Modern evolution (2023\u20132025)"}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Grouped-query attention (GQA) \u2014 now universal:"})," Standard multi-head attention allocates one set of key-value pairs per query head. GQA groups multiple query heads to share a single KV head, reducing KV cache memory proportionally. LLaMA 3 8B uses 32 query heads sharing 8 KV heads (4:1 ratio), cutting KV cache size by 4\xd7 with negligible accuracy loss. GQA is now the de facto standard. \u2192 see ",(0,a.jsx)(n.a,{href:"/ai-systems-engineering/docs/model-inference-core/kv-cache",children:"KV cache"})," for how this affects memory allocation at inference."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Multi-head latent attention (MLA) \u2014 DeepSeek V2/V3 (2024):"})," MLA compresses the key-value representation into a low-dimensional latent vector (dimension d_c \u226a n_h \xd7 d_h). Only this latent vector is stored in the cache and expanded back during attention computation. At 68.75% KV compression: -0.29% performance loss. At 87.5% compression: modest further degradation. MLA is appearing in Kimi K2, GLM-5, and other 2025 architectures."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"RoPE positional encoding \u2014 69.8% adoption:"})," Rotary position embedding (RoPE) encodes position by rotating the query and key vectors in attention by a position-dependent angle, rather than adding a sinusoidal offset to the embedding. This enables better length extrapolation than the original sinusoidal encoding, though reliable extension to contexts beyond training still requires explicit methods like YaRN. \u2192 see ",(0,a.jsx)(n.a,{href:"/ai-systems-engineering/docs/model-inference-core/context-window",children:"Context window"})," for how positional encoding limits and extensions interact with generation."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"SwiGLU activation \u2014 71.7% adoption:"})," SwiGLU replaces ReLU in the FFN with a gated linear unit: ",(0,a.jsx)(n.code,{children:"SwiGLU(x, W, V) = Swish(xW) \u2299 (xV)"}),". The gating mechanism provides smoother gradients and consistently outperforms GeLU and ReLU at the same parameter count."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Hybrid transformer + SSM (2024\u20132025):"})," State Space Models (Mamba/Mamba-2) process sequences in linear time with no KV cache. NVIDIA's Nemotron-H replaces 92% of attention layers with Mamba-2 blocks, achieving up to 3\xd7 higher throughput at long contexts. AI21's Jamba combines Mamba, transformer, and mixture-of-experts (MoE) layers for 256K context windows. This is an active research front, not yet production-settled."]}),"\n",(0,a.jsxs)(n.p,{children:[(0,a.jsx)(n.strong,{children:"Post-norm revisited:"})," Five years of pre-norm dominance is being challenged. OLMo 2 and Gemma 3 return to post-norm paired with QK-normalization (normalizing query and key vectors before attention) to prevent logit explosion at depth, claiming better training stability at scale. Whether this trend continues is unresolved as of May 2026."]}),"\n",(0,a.jsx)(n.h3,{id:"what-the-2017-paper-got-right-and-wrong",children:"What the 2017 paper got right and wrong"}),"\n",(0,a.jsxs)(n.table,{children:[(0,a.jsx)(n.thead,{children:(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.th,{children:"Component"}),(0,a.jsx)(n.th,{children:"2017 original"}),(0,a.jsx)(n.th,{children:"2025 default"})]})}),(0,a.jsxs)(n.tbody,{children:[(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Positional encoding"}),(0,a.jsx)(n.td,{children:"Sinusoidal (absolute)"}),(0,a.jsx)(n.td,{children:"RoPE (relative, rotary)"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Normalization placement"}),(0,a.jsx)(n.td,{children:"Post-norm"}),(0,a.jsx)(n.td,{children:"Pre-norm (RMSNorm)"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"FFN activation"}),(0,a.jsx)(n.td,{children:"ReLU"}),(0,a.jsx)(n.td,{children:"SwiGLU"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Generative architecture"}),(0,a.jsx)(n.td,{children:"Encoder-decoder"}),(0,a.jsx)(n.td,{children:"Decoder-only"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Residual connection structure"}),(0,a.jsx)(n.td,{children:"Retained unchanged"}),(0,a.jsx)(n.td,{children:"Retained unchanged"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Multi-head attention concept"}),(0,a.jsx)(n.td,{children:"Retained (adapted to GQA/MLA)"}),(0,a.jsx)(n.td,{children:"Retained (adapted)"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Alternating attention-FFN blocks"}),(0,a.jsx)(n.td,{children:"Retained unchanged"}),(0,a.jsx)(n.td,{children:"Retained unchanged"})]})]})]}),"\n",(0,a.jsx)(n.p,{children:"The residual connection structure, the multi-head attention concept, and the alternating attention-FFN block pattern survived intact. Everything else was replaced."}),"\n",(0,a.jsx)(n.h3,{id:"gotchas--production-behavior",children:"Gotchas & production behavior"}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.strong,{children:"Model selection pitfalls"})}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:[(0,a.jsx)(n.strong,{children:"Encoder-only for generation, decoder-only for classification."})," BERT cannot generate text \u2014 it produces bidirectional representations with no causal ordering. Using a GPT-style decoder for classification when you have 500+ labeled samples wastes compute: fine-tuned BERT achieves ~57.6% accuracy on text classification vs ~18% from prompting a decoder-only model zero-shot on the same task. The rule: if you have labels, use an encoder; if you're generating, use a decoder."]}),"\n",(0,a.jsxs)(n.li,{children:[(0,a.jsx)(n.strong,{children:'"Decoder-only won because it\'s architecturally superior."'})," The actual driver was the shift to instruction-following \u2014 encoder-decoder required per-task classification heads, decoder-only simplified fine-tuning to a single objective. When compute is held constant and instruction tuning is applied, encoder-decoder matches or exceeds decoder-only (RedLLM 8B: 59.69 vs DecLLM 58.26 zero-shot). The architectural victory was cultural, not empirical."]}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.strong,{children:"Depth and width allocation pitfalls"})}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:[(0,a.jsx)(n.strong,{children:'"More layers = better."'})," Research shows optimal hidden dimension width grows 2.8\xd7 faster than depth. At 7B scale, a 64-layer model (6.38B params) underperforms a 32-layer model (6.86B params) by 0.12 nats \u2014 strictly worse despite more layers. Around 50% of layers in deep pre-norm models are near-identity in practice. Prefer adding width before adding layers once you are past 32 layers. Never use layer count as a proxy for model quality."]}),"\n",(0,a.jsxs)(n.li,{children:[(0,a.jsx)(n.strong,{children:"Layer count in model names is not standardized."}),' A "32-layer" model in one family may use different d_model, heads, and GQA configurations than a "32-layer" in another. Always look at d_model and active parameters, not layer count alone.']}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.strong,{children:"Normalization placement pitfalls"})}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsxs)(n.li,{children:[(0,a.jsx)(n.strong,{children:"Swapping pre-norm and post-norm configs is not cosmetic."})," Post-norm (BERT, original Transformer) requires a mandatory learning rate warmup \u2014 without it, training diverges from gradient explosion. Pre-norm (LLaMA, Mistral) is stable without warmup. Copying a modern LLaMA config into a post-norm architecture and omitting warmup produces silent training failures that may not surface until after hours of compute."]}),"\n",(0,a.jsxs)(n.li,{children:[(0,a.jsx)(n.strong,{children:"Adding QK-normalization for deep models."})," At depths beyond 30 layers with post-norm, attention logits can explode. QK-norm (normalizing Q and K vectors before the dot product) prevents this. It appeared in Gemma and is required when reviving post-norm at scale."]}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.strong,{children:"FFN parameter mass is ignored during compression"})}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsx)(n.li,{children:"Practitioners focus on attention heads during pruning and quantization because of the paper's name and the conceptual prominence of attention. FFN parameters outnumber MHA parameters at ~2:1 per layer. In GPT-2: MHA \u2248 2.36M parameters per layer; FFN \u2248 4.7M per layer. Token embeddings \u2248 38.6M total \u2014 nearly matching all attention parameters combined across the whole model. Compute the FFN-vs-attention ratio explicitly before any compression work."}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.strong,{children:"Residual stream mental model"})}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsx)(n.li,{children:'The common description ("residual connections add back what the layer missed") produces wrong intuitions about pruning. The accurate model: layers write small deltas to a shared residual stream that passes through largely unchanged. This explains why removing individual layers produces small quality drops \u2014 any single layer\'s contribution is marginal \u2014 and why gradient flow stays healthy in 100+ layer models.'}),"\n"]}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.h2,{id:"why-it-matters",children:"Why it matters"}),"\n",(0,a.jsxs)(n.p,{children:["This topic sits at the ",(0,a.jsx)(n.strong,{children:"Model serving"})," layer and is the structural prerequisite for every topic in section 01. Without knowing which transformer variant is in use \u2014 encoder-only, decoder-only, or encoder-decoder \u2014 the downstream decisions in this section (KV cache sizing, batching strategy, attention mechanism choice, context window limits) are made without a coherent model of the system being optimized."]}),"\n",(0,a.jsx)(n.p,{children:"The parameter distribution fact alone has direct dollar consequences: a quantization pass that compresses attention from FP16 to INT4 while leaving FFN at FP16 reduces total model size by roughly 17%, not 50%. In a 70B model, that gap is tens of gigabytes of VRAM that an engineer might have incorrectly planned away."}),"\n",(0,a.jsx)(n.p,{children:"The concrete anchor: LLaMA 3 8B's GQA configuration (32 query heads, 8 KV heads) reduces KV cache memory by 4\xd7 compared to full multi-head attention \u2014 directly determining whether a 100K-token context fits on a single A100 or requires multi-GPU serving."}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.h2,{id:"key-terms",children:"Key terms"}),"\n",(0,a.jsxs)(n.table,{children:[(0,a.jsx)(n.thead,{children:(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.th,{children:"Term"}),(0,a.jsx)(n.th,{children:"Meaning"})]})}),(0,a.jsxs)(n.tbody,{children:[(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Encoder-only"}),(0,a.jsx)(n.td,{children:"Transformer variant where every token attends to every other token bidirectionally; produces contextualized representations, cannot generate autoregressively"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Decoder-only"}),(0,a.jsx)(n.td,{children:"Transformer variant using causal (masked) self-attention; each token sees only prior tokens; the dominant architecture for generative LLMs"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Encoder-decoder"}),(0,a.jsx)(n.td,{children:"Transformer variant with a bidirectional encoder stack and a separate autoregressive decoder stack connected via cross-attention"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Causal mask"}),(0,a.jsx)(n.td,{children:"Triangular mask applied to attention scores that sets future-position scores to -inf, preventing each token from attending to tokens not yet generated"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Residual stream"}),(0,a.jsx)(n.td,{children:"The vector that passes through all N transformer layers, with each sublayer writing a small delta rather than transforming it wholesale"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Pre-norm"}),(0,a.jsx)(n.td,{children:"Layer normalization applied to the input of each sublayer (before attention or FFN), the dominant configuration since GPT-2; stable without warmup"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"Post-norm"}),(0,a.jsx)(n.td,{children:"Layer normalization applied to the output of each sublayer (after adding the residual); requires warmup to avoid gradient explosion"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"GQA (Grouped-query attention)"}),(0,a.jsx)(n.td,{children:"Attention variant where multiple query heads share one KV head, reducing KV cache size proportionally; standard since LLaMA 2"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"MLA (Multi-head latent attention)"}),(0,a.jsx)(n.td,{children:"DeepSeek's KV compression technique: caches a low-dimensional latent vector per layer instead of full KV heads; 68\u201388% KV reduction"})]}),(0,a.jsxs)(n.tr,{children:[(0,a.jsx)(n.td,{children:"SwiGLU"}),(0,a.jsxs)(n.td,{children:["Gated activation function used in modern FFN sublayers: ",(0,a.jsx)(n.code,{children:"Swish(xW) \u2299 (xV)"}),"; adopted in LLaMA, Mistral, and ~72% of 2025 models"]})]})]})]}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.h2,{id:"code--demo",children:"Code / demo"}),"\n",(0,a.jsxs)(n.p,{children:["The snippet below calculates the parameter count for the attention and FFN sublayers of a single transformer block given d_model and the expansion ratio, then shows the FFN",":attention"," ratio. No GPU or API key required."]}),"\n",(0,a.jsx)(n.pre,{children:(0,a.jsx)(n.code,{className:"language-python",children:'# No pip install needed \u2014 standard library only\n\ndef block_params(d_model, n_heads, n_kv_heads=None, ffn_expansion=4.0):\n    if n_kv_heads is None:\n        n_kv_heads = n_heads\n    d_head = d_model // n_heads\n    attn = (d_model * n_heads * d_head       # Q\n            + d_model * n_kv_heads * d_head  # K\n            + d_model * n_kv_heads * d_head  # V\n            + n_heads * d_head * d_model)    # O\n    d_ff = int(ffn_expansion * d_model)\n    ffn = d_model * d_ff + d_ff * d_model\n    return attn, ffn, round(ffn / attn, 2)\n\nconfigs = [\n    ("BERT-base",   768,  12, None, 4.0),\n    ("LLaMA 3 8B", 4096,  32,    8, 8/3),  # SwiGLU expansion ratio\n]\n\nprint(f"{\'Model\':<14} {\'Attn params\':>14} {\'FFN params\':>14} {\'FFN:Attn\':>10}")\nprint("-" * 56)\nfor name, d, nh, nkv, exp in configs:\n    attn, ffn, ratio = block_params(d, nh, nkv, exp)\n    print(f"{name:<14} {attn:>14,} {ffn:>14,} {ratio:>10.2f}")\n'})}),"\n",(0,a.jsx)(n.p,{children:"Expected output:"}),"\n",(0,a.jsx)(n.pre,{children:(0,a.jsx)(n.code,{children:"Model          Attn params     FFN params   FFN:Attn\n--------------------------------------------------------\nBERT-base        2,359,296      4,718,592       2.00\nLLaMA 3 8B      18,874,368     45,088,768       2.39\n"})}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.h2,{id:"my-notes",children:"My notes"}),"\n",(0,a.jsxs)(n.ul,{children:["\n",(0,a.jsx)(n.li,{children:"The post-norm vs pre-norm debate is not settled. OLMo 2 and Gemma 3 are actively revisiting post-norm with QK-normalization, arguing it achieves better training stability at scale than pre-norm. Five years of consensus is being challenged \u2014 worth watching over the next 12 months."}),"\n",(0,a.jsx)(n.li,{children:"Encoder-decoder models may be underused for long-context tasks. The research shows they extrapolate to longer contexts better than decoder-only, and match decoder-only quality when instruction-tuned with equal compute. The industry shift to decoder-only was driven by the GPT cultural moment, not a clean empirical victory."}),"\n",(0,a.jsx)(n.li,{children:"The \"residual stream as shared memory\" mental model (layers write deltas, not transformations) changes how you reason about layer pruning. A layer that appears near-identity isn't broken \u2014 it's doing very little, which is why removing it hurts minimally. About 50% of layers in deep pre-norm models are near-identity; this is normal and expected behavior."}),"\n",(0,a.jsxs)(n.li,{children:["GQA is now table stakes for any new decoder-only model, but the KV head count is a tunable hyperparameter that interacts directly with both quality and cache memory. Engineers often accept the published ratio (e.g., 4:1) without evaluating whether their serving context length and batch size would benefit from a different ratio. \u2192 see ",(0,a.jsx)(n.a,{href:"/ai-systems-engineering/docs/model-inference-core/kv-cache",children:"KV cache"})," for the memory arithmetic."]}),"\n",(0,a.jsx)(n.li,{children:"Hybrid SSM + transformer architectures (Nemotron-H, Jamba) claim 3\xd7 throughput improvements at long contexts. These are early production numbers on specific workloads \u2014 not yet generalizable benchmarks. The tradeoff is that SSM layers lack the KV cache interpretability tools and may behave differently during speculative decoding."}),"\n"]}),"\n",(0,a.jsx)(n.p,{children:(0,a.jsx)(n.em,{children:"Last researched: May 2026"})}),"\n",(0,a.jsx)(n.hr,{}),"\n",(0,a.jsx)(n.h2,{id:"resources",children:"Resources"}),"\n",(0,a.jsxs)(n.ol,{children:["\n",(0,a.jsxs)(n.li,{children:['Vaswani et al., "Attention Is All You Need" (2017) \u2014 ',(0,a.jsx)(n.a,{href:"https://arxiv.org/abs/1706.03762",children:"https://arxiv.org/abs/1706.03762"})]}),"\n",(0,a.jsxs)(n.li,{children:['"The Crystallization of Transformer Architectures (2017\u20132025)" \u2014 a 53-model empirical analysis of which design choices survived \u2014 ',(0,a.jsx)(n.a,{href:"https://jytan.net/blog/2025/transformer-architectures/",children:"https://jytan.net/blog/2025/transformer-architectures/"})]}),"\n",(0,a.jsxs)(n.li,{children:['"Towards Economical Inference: MLA in Any Transformer-based LLMs" (2025) \u2014 ',(0,a.jsx)(n.a,{href:"https://arxiv.org/abs/2502.14837",children:"https://arxiv.org/abs/2502.14837"})]}),"\n"]})]})}function h(e={}){const{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,a.jsx)(n,{...e,children:(0,a.jsx)(c,{...e})}):c(e)}},1550(e,n,t){t.d(n,{A:()=>r});const r=t.p+"assets/images/transformer-d19e0d76460758b87765ec4958830e36.png"},8453(e,n,t){t.d(n,{R:()=>o,x:()=>s});var r=t(6540);const a={},i=r.createContext(a);function o(e){const n=r.useContext(i);return r.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function s(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),r.createElement(i.Provider,{value:n},e.children)}}}]);